8263	\begin{lemma}[Slice lift of the $\operatorname{Option}$-coproduct splitting]
8264	  \label{lem:over_sigmaOptionIso}
8265	  \lean{AlgebraicGeometry.overSigmaOptionIso}
8266	  \uses{lem:sigmaOptionIso}
8267	  Let \(\mathrm{legs} : \operatorname{Option}\alpha \to \operatorname{Over} X\) be a family of objects
8268	  of the slice over \(X\). The splitting of Lemma~\ref{lem:sigmaOptionIso} lifts to an isomorphism in
8269	  \(\operatorname{Over} X\) between the coproduct slice object and the binary-split slice object:
8270	  \[
8271	    \operatorname{Over.mk}\bigl(\operatorname{Sigma.desc}(o \mapsto (\mathrm{legs}\,o).\mathrm{hom})\bigr)
8272	      \;\cong\;
8273	    \operatorname{Over.mk}\bigl(\operatorname{coprod.desc}\,(\mathrm{legs}\,\operatorname{none}).\mathrm{hom}\,
8274	      (\operatorname{Sigma.desc}(a \mapsto (\mathrm{legs}\,(\operatorname{some} a)).\mathrm{hom}))\bigr).
8275	  \]
8276	\end{lemma}
8277	\begin{proof}
8278	  \uses{lem:sigmaOptionIso}
8279	  Build the slice isomorphism as \(\operatorname{Over.isoMk}\) of the underlying-scheme isomorphism
8280	  \(\operatorname{sigmaOptionIso}(o \mapsto (\mathrm{legs}\,o).\mathrm{left})\)
8281	  (Lemma~\ref{lem:sigmaOptionIso}), together with the verification that its forward map commutes with
8282	  the two structure arrows. The latter is checked componentwise: on each \(\operatorname{none}\) and
8283	  \(\operatorname{some} a\) component both descent maps reduce to \((\mathrm{legs}\,o).\mathrm{hom}\) by
8284	  the universal properties of each coproduct.
8285	\end{proof}
